code: async (page) => {
  await page.click('tr[data-expense-id="1499"]');
  await page.waitForTimeout(500);
  const btn = page.locator('text=View Receipt').first();
  const context = page.context();
  const popupPromise = context.waitForEvent('page', { timeout: 5000 }).catch(() => null);
  await btn.click();
  const popup = await popupPromise;
  if (!popup) return { popup: null };
  await popup.waitForLoadState('load').catch(()=>{});
  const url = popup.url();
  const text = await popup.locator('body').innerText().catch(() => '(no body)');
  return { url, text: text.slice(0, 300) };
}
